from __future__ import annotations

from dataclasses import replace
from pathlib import Path
from typing import Callable, TypeVar

from lit.merge_ops import MergeResult, merge_revision
from lit.rebase_ops import RebaseResult, rebase_onto
from lit.repository import CheckoutRecord, Repository
from lit_gui.backend import SnapshotFeedback, SnapshotSelections, build_snapshot
from lit_gui.contracts import RepositorySession, SessionSnapshot
from lit_gui.persistence import RecentRepositoriesStore

_T = TypeVar("_T")


class LitRepositorySession(RepositorySession):
    def __init__(
        self,
        root: Path | None = None,
        *,
        recent_store: RecentRepositoriesStore | None = None,
    ) -> None:
        self._recent_store = recent_store or RecentRepositoriesStore()
        self._root = self._resolve_root(root or Path.cwd())
        self._repository: Repository | None = self._reload_repository(self._root)
        self._recent_roots: tuple[Path, ...] = self._recent_store.load()
        self._selections = SnapshotSelections()
        self._feedback: SnapshotFeedback | None = None
        self._snapshot = self._rebuild_snapshot()

    def snapshot(self) -> SessionSnapshot:
        return self._snapshot

    def open_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_open_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        self._repository = self._reload_repository(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        if self._repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="info",
                    message=f"No .lit metadata detected at {self._root}.",
                )
            )
        return self._rebuild_snapshot(
            feedback=SnapshotFeedback(
                level="success",
                message=f"Opened lit repository at {self._root}.",
            )
        )

    def initialize_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_initialize_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        already_initialized = (self._root / ".lit").is_dir()
        self._repository = Repository.create(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        message = (
            f"Opened existing lit repository at {self._root}."
            if already_initialized
            else f"Initialized empty lit repository in {self._repository.layout.dot_lit}."
        )
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level="success", message=message))

    def refresh(self) -> SessionSnapshot:
        self._repository = self._reload_repository(self._root)
        message = (
            f"Repository refreshed at {self._root}."
            if self._repository is not None
            else f"No .lit metadata detected at {self._root}."
        )
        level = "success" if self._repository is not None else "info"
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level=level, message=message))

    def stage_paths(self, paths: tuple[str, ...]) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.stage(paths),
            on_success=lambda staged: SnapshotFeedback(
                level="success",
                message=f"staged {len(staged)} path(s)",
            ),
        )

    def restore_paths(self, paths: tuple[str, ...], *, source: str | None = None) -> SessionSnapshot:
        source_label = source or "HEAD"
        return self._run_repository_action(
            lambda repository: repository.restore(paths, source=source),
            on_success=lambda restored: SnapshotFeedback(
                level="success",
                message=f"restored {len(restored)} path(s) from {source_label}",
            ),
        )

    def commit(self, message: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.commit(message),
            on_success=lambda commit_id: self._commit_feedback(commit_id, message),
            update_selections=lambda commit_id: replace(self._selections, commit_id=commit_id),
        )

    def select_change(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, change_path=path)
        return self._rebuild_snapshot()

    def select_commit(self, commit_id: str) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_id=commit_id, commit_path=None)
        return self._rebuild_snapshot()

    def select_commit_path(self, path: str | None) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_path=path)
        return self._rebuild_snapshot()

    def create_branch(self, name: str, *, start_point: str | None = "HEAD") -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.create_branch(name, start_point=start_point),
            on_success=lambda branch: SnapshotFeedback(
                level="success",
                message=f"{branch.name} -> {branch.commit_id[:12] if branch.commit_id else 'unborn'}",
            ),
            update_selections=lambda branch: replace(self._selections, branch_name=branch.name),
        )

    def select_branch(self, branch_name: str) -> SessionSnapshot:
        self._selections = replace(self._selections, branch_name=branch_name)
        return self._rebuild_snapshot()

    def checkout(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.checkout(revision),
            on_success=self._checkout_feedback,
            update_selections=self._checkout_selections,
        )

    def merge(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: merge_revision(repository, revision),
            on_success=lambda result: SnapshotFeedback(level="success", message=result.message),
            update_selections=self._merge_selections,
        )

    def abort_merge(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_merge_state()
            if state is None:
                raise ValueError("No merge in progress.")
            repository.apply_commit(
                state.current_commit,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_merge()
            return state.current_commit

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Merge state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def rebase(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: rebase_onto(repository, revision),
            on_success=lambda result: SnapshotFeedback(level="success", message=result.message),
            update_selections=self._rebase_selections,
        )

    def abort_rebase(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_rebase_state()
            if state is None:
                raise ValueError("No rebase in progress.")
            branch_name = repository.current_branch_name()
            if branch_name is not None:
                repository.write_branch(branch_name, state.original_head)
            repository.apply_commit(
                state.original_head,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_rebase()
            return state.original_head

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Rebase state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def select_file(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, file_path=path)
        return self._rebuild_snapshot()

    def _run_repository_action(
        self,
        operation: Callable[[Repository], _T],
        *,
        on_success: Callable[[_T], SnapshotFeedback],
        update_selections: Callable[[_T], SnapshotSelections] | None = None,
    ) -> SessionSnapshot:
        repository = self._repository
        if repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="error",
                    message="Open or initialize a repository first.",
                )
            )

        try:
            result = operation(repository)
        except (FileNotFoundError, RuntimeError, ValueError) as error:
            self._repository = self._reload_repository(self._root)
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=str(error))
            )

        if update_selections is not None:
            self._selections = update_selections(result)
        self._repository = self._reload_repository(self._root)
        return self._rebuild_snapshot(feedback=on_success(result))

    def _rebuild_snapshot(self, *, feedback: SnapshotFeedback | None = None) -> SessionSnapshot:
        if feedback is not None:
            self._feedback = feedback
        self._snapshot, self._selections = build_snapshot(
            root=self._root,
            repository=self._repository,
            recent_roots=self._recent_roots,
            selections=self._selections,
            feedback=self._feedback,
        )
        return self._snapshot

    def _remember_recent(self, root: Path, *, persist: bool = False) -> None:
        ordered = [root]
        ordered.extend(existing for existing in self._recent_roots if existing != root)
        self._recent_roots = tuple(ordered[:5])
        if persist:
            self._recent_store.save(self._recent_roots)

    def _reload_repository(self, root: Path) -> Repository | None:
        try:
            return Repository.open(root)
        except FileNotFoundError:
            return None

    def _resolve_root(self, root: Path) -> Path:
        return Path(root).expanduser().resolve()

    def _validate_open_root(self, root: Path) -> str | None:
        if not root.exists():
            return f"Folder not found: {root}."
        if not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _validate_initialize_root(self, root: Path) -> str | None:
        if root.exists() and not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _commit_feedback(self, commit_id: str, message: str) -> SnapshotFeedback:
        branch_name = self._repository.current_branch_name() if self._repository is not None else None
        label = branch_name or "detached"
        return SnapshotFeedback(
            level="success",
            message=f"[{label} {commit_id[:12]}] {message}",
        )

    def _checkout_feedback(self, result: CheckoutRecord) -> SnapshotFeedback:
        if result.branch_name is not None:
            return SnapshotFeedback(
                level="success",
                message=f"switched to branch {result.branch_name}",
            )
        target = "unborn" if result.commit_id is None else result.commit_id[:12]
        return SnapshotFeedback(level="success", message=f"detached HEAD at {target}")

    def _checkout_selections(self, result: CheckoutRecord) -> SnapshotSelections:
        return replace(
            self._selections,
            branch_name=result.branch_name,
            commit_id=result.commit_id,
            change_path=None,
        )

    def _merge_selections(self, result: MergeResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

    def _rebase_selections(self, result: RebaseResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from enum import StrEnum
from pathlib import Path
from typing import Literal


class NavigationTarget(StrEnum):
    HOME = "home"
    CHANGES = "changes"
    HISTORY = "history"
    BRANCHES = "branches"
    FILES = "files"


VIEW_ORDER: tuple[NavigationTarget, ...] = (
    NavigationTarget.HOME,
    NavigationTarget.CHANGES,
    NavigationTarget.HISTORY,
    NavigationTarget.BRANCHES,
    NavigationTarget.FILES,
)


class DetailSlotId(StrEnum):
    SELECTION = "selection"
    METADATA = "metadata"
    GUIDANCE = "guidance"


@dataclass(frozen=True, slots=True)
class OperationSummary:
    kind: Literal["merge", "rebase"]
    summary: str
    conflicts: tuple[str, ...] = ()


@dataclass(frozen=True, slots=True)
class RepositoryDescriptor:
    name: str
    root: Path | None = None
    current_branch: str | None = None
    head_commit: str | None = None
    status_text: str = ""
    is_lit_repository: bool = False
    operation: OperationSummary | None = None


@dataclass(frozen=True, slots=True)
class RecentRepository:
    name: str
    root: Path
    summary: str = ""
    is_lit_repository: bool = False


@dataclass(frozen=True, slots=True)
class SummaryItem:
    label: str
    value: str


@dataclass(frozen=True, slots=True)
class DetailSlotState:
    slot_id: DetailSlotId
    title: str
    body: str


@dataclass(frozen=True, slots=True)
class DetailPaneState:
    selection: DetailSlotState
    metadata: DetailSlotState
    guidance: DetailSlotState

    @classmethod
    def placeholder(
        cls,
        *,
        selection_title: str,
        selection_body: str,
        metadata_title: str,
        metadata_body: str,
        guidance_title: str,
        guidance_body: str,
    ) -> "DetailPaneState":
        return cls(
            selection=DetailSlotState(
                slot_id=DetailSlotId.SELECTION,
                title=selection_title,
                body=selection_body,
            ),
            metadata=DetailSlotState(
                slot_id=DetailSlotId.METADATA,
                title=metadata_title,
                body=metadata_body,
            ),
            guidance=DetailSlotState(
                slot_id=DetailSlotId.GUIDANCE,
                title=guidance_title,
                body=guidance_body,
            ),
        )

    def slots(self) -> tuple[DetailSlotState, ...]:
        return (self.selection, self.metadata, self.guidance)


@dataclass(frozen=True, slots=True)
class BaseViewState:
    route: NavigationTarget
    title: str
    subtitle: str
    detail: DetailPaneState


@dataclass(frozen=True, slots=True)
class ChangedPath:
    path: str
    change_kind: Literal["added", "modified", "deleted", "untracked"]
    staged: bool = False
    note: str = ""


@dataclass(frozen=True, slots=True)
class CommitSummary:
    commit_id: str
    message: str
    author: str = ""
    committed_at: str = ""
    changed_paths: tuple[str, ...] = ()


@dataclass(frozen=True, slots=True)
class BranchSummary:
    name: str
    commit_id: str | None = None
    is_current: bool = False
    note: str = ""


@dataclass(frozen=True, slots=True)
class FileNode:
    path: str
    display_name: str
    node_kind: Literal["directory", "file"]
    depth: int = 0


@dataclass(frozen=True, slots=True)
class HomeViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    recent_repositories: tuple[RecentRepository, ...] = ()
    call_to_action: str = ""


@dataclass(frozen=True, slots=True)
class ChangesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    staged: tuple[ChangedPath, ...] = ()
    unstaged: tuple[ChangedPath, ...] = ()
    selected_path: str | None = None
    can_commit: bool = False
    commit_message_hint: str = ""


@dataclass(frozen=True, slots=True)
class HistoryViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    commits: tuple[CommitSummary, ...] = ()
    selected_commit: str | None = None
    selected_path: str | None = None


@dataclass(frozen=True, slots=True)
class BranchesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    branches: tuple[BranchSummary, ...] = ()
    selected_branch: str | None = None
    can_checkout: bool = False


@dataclass(frozen=True, slots=True)
class FilesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    tree: tuple[FileNode, ...] = ()
    selected_path: str | None = None


ShellViewState = HomeViewState | ChangesViewState | HistoryViewState | BranchesViewState | FilesViewState


@dataclass(frozen=True, slots=True)
class SessionSnapshot:
    repository: RepositoryDescriptor | None
    home: HomeViewState
    changes: ChangesViewState
    history: HistoryViewState
    branches: BranchesViewState
    files: FilesViewState

    @property
    def default_view(self) -> NavigationTarget:
        if self.repository is not None and self.repository.is_lit_repository:
            return NavigationTarget.CHANGES
        return NavigationTarget.HOME

    def for_view(self, target: NavigationTarget) -> ShellViewState:
        return {
            NavigationTarget.HOME: self.home,
            NavigationTarget.CHANGES: self.changes,
            NavigationTarget.HISTORY: self.history,
            NavigationTarget.BRANCHES: self.branches,
            NavigationTarget.FILES: self.files,
        }[target]


class RepositorySession(ABC):
    """Desktop GUI boundary: `lit_gui` is a PySide6 client over the existing Python `lit` backend. `RepositorySession` is the only query and mutation gateway and returns immutable DTOs for all views. The shell owns three stable regions (sidebar, active center view, right detail panel); feature views may fill slots but must not rewire the shell. Views do not import `lit.repository` directly and do not persist metadata inside user repositories."""

    @abstractmethod
    def snapshot(self) -> SessionSnapshot:
        """Return the latest immutable snapshot for all shell views."""

    @abstractmethod
    def open_repository(self, root: Path) -> SessionSnapshot:
        """Open an existing folder and rebuild every view state."""

    @abstractmethod
    def initialize_repository(self, root: Path) -> SessionSnapshot:
        """Initialize a repository and rebuild every view state."""

    @abstractmethod
    def refresh(self) -> SessionSnapshot:
        """Reload the active repository into a fresh snapshot."""

    @abstractmethod
    def stage_paths(self, paths: tuple[str, ...]) -> SessionSnapshot:
        """Stage the provided paths for commit."""

    @abstractmethod
    def restore_paths(self, paths: tuple[str, ...], *, source: str | None = None) -> SessionSnapshot:
        """Restore paths from the working tree or a specific revision."""

    @abstractmethod
    def commit(self, message: str) -> SessionSnapshot:
        """Create a commit and return the updated shell snapshot."""

    @abstractmethod
    def select_change(self, path: str) -> SessionSnapshot:
        """Update the selected change and its shared detail slots."""

    @abstractmethod
    def select_commit(self, commit_id: str) -> SessionSnapshot:
        """Update the selected history item and its shared detail slots."""

    @abstractmethod
    def select_commit_path(self, path: str | None) -> SessionSnapshot:
        """Update the selected changed file for the current history item."""

    @abstractmethod
    def create_branch(self, name: str, *, start_point: str | None = "HEAD") -> SessionSnapshot:
        """Create a branch and return the updated shell snapshot."""

    @abstractmethod
    def select_branch(self, branch_name: str) -> SessionSnapshot:
        """Update the selected branch and its shared detail slots."""

    @abstractmethod
    def checkout(self, revision: str) -> SessionSnapshot:
        """Switch to another branch or detach at a commit."""

    @abstractmethod
    def merge(self, revision: str) -> SessionSnapshot:
        """Start or complete a merge and return the updated shell snapshot."""

    @abstractmethod
    def abort_merge(self) -> SessionSnapshot:
        """Abort the active merge state and return the updated shell snapshot."""

    @abstractmethod
    def rebase(self, revision: str) -> SessionSnapshot:
        """Start or complete a rebase and return the updated shell snapshot."""

    @abstractmethod
    def abort_rebase(self) -> SessionSnapshot:
        """Abort the active rebase state and return the updated shell snapshot."""

    @abstractmethod
    def select_file(self, path: str) -> SessionSnapshot:
        """Update the selected file or tree node and its shared detail slots."""

from __future__ import annotations

from PySide6 import QtWidgets

from lit_gui.contracts import (
    BranchesViewState,
    ChangesViewState,
    FilesViewState,
    HistoryViewState,
    HomeViewState,
    NavigationTarget,
    SessionSnapshot,
    SummaryItem,
    VIEW_ORDER,
)


class PlaceholderView(QtWidgets.QWidget):
    def __init__(
        self,
        state: HomeViewState | ChangesViewState | HistoryViewState | BranchesViewState | FilesViewState,
        parent: QtWidgets.QWidget | None = None,
    ) -> None:
        super().__init__(parent)
        self.route = state.route
        self.state = state
        self.title_label = QtWidgets.QLabel(state.title)
        self.subtitle_label = QtWidgets.QLabel(state.subtitle)
        self.section_titles: tuple[str, ...] = ()
        self._sections: list[tuple[QtWidgets.QGroupBox, QtWidgets.QLabel]] = []

        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(12)

        self.title_label.setWordWrap(True)
        self.subtitle_label.setWordWrap(True)
        layout.addWidget(self.title_label)
        layout.addWidget(self.subtitle_label)

        for title, lines in _sections_for_state(state):
            group = QtWidgets.QGroupBox()
            group.setTitle(title)
            group_layout = QtWidgets.QVBoxLayout(group)
            label = QtWidgets.QLabel()
            label.setWordWrap(True)
            group_layout.addWidget(label)
            self._sections.append((group, label))
            layout.addWidget(group)

        layout.addStretch(1)
        self.apply_state(state)

    def apply_state(
        self,
        state: HomeViewState | ChangesViewState | HistoryViewState | BranchesViewState | FilesViewState,
    ) -> None:
        self.state = state
        self.title_label.setText(state.title)
        self.subtitle_label.setText(state.subtitle)
        sections = tuple(_sections_for_state(state))
        self.section_titles = tuple(title for title, _ in sections)
        for index, (title, lines) in enumerate(sections):
            group, label = self._sections[index]
            group.setTitle(title)
            label.setText("\n".join(lines))


def build_placeholder_views(snapshot: SessionSnapshot) -> dict[NavigationTarget, PlaceholderView]:
    return {target: PlaceholderView(snapshot.for_view(target)) for target in VIEW_ORDER}


def _sections_for_state(
    state: HomeViewState | ChangesViewState | HistoryViewState | BranchesViewState | FilesViewState,
) -> tuple[tuple[str, tuple[str, ...]], ...]:
    if isinstance(state, HomeViewState):
        recent = tuple(
            f"{entry.name}: {entry.root}"
            for entry in state.recent_repositories
        ) or ("No recent repositories recorded yet.",)
        return (
            ("Highlights", _summary_lines(state.highlights)),
            ("Recent Repositories", recent),
            ("Next Step", (state.call_to_action,)),
        )
    if isinstance(state, ChangesViewState):
        staged = tuple(
            f"{entry.path} [{entry.change_kind}]"
            for entry in state.staged
        ) or ("No staged paths yet.",)
        unstaged = tuple(
            f"{entry.path} [{entry.change_kind}]"
            for entry in state.unstaged
        ) or ("No unstaged paths yet.",)
        return (
            ("Summary", _summary_lines(state.highlights)),
            ("Staged", staged),
            ("Unstaged", unstaged),
            ("Commit", (state.commit_message_hint,)),
        )
    if isinstance(state, HistoryViewState):
        commits = tuple(
            f"{entry.commit_id}: {entry.message}"
            for entry in state.commits
        ) or ("No commits loaded yet.",)
        return (
            ("Summary", _summary_lines(state.highlights)),
            ("Timeline", commits),
        )
    if isinstance(state, BranchesViewState):
        branches = tuple(
            f"{'* ' if entry.is_current else '  '}{entry.name}"
            for entry in state.branches
        ) or ("No branches loaded yet.",)
        return (
            ("Summary", _summary_lines(state.highlights)),
            ("Branch List", branches),
        )
    tree = tuple(
        f"{'  ' * entry.depth}{entry.display_name}"
        for entry in state.tree
    ) or ("No repository tree loaded yet.",)
    return (
        ("Summary", _summary_lines(state.highlights)),
        ("Repository Tree", tree),
    )


def _summary_lines(items: tuple[SummaryItem, ...]) -> tuple[str, ...]:
    return tuple(f"{item.label}: {item.value}" for item in items) or ("No summary available yet.",)

from __future__ import annotations

import importlib
import sys
import tomllib
import types
from dataclasses import FrozenInstanceError
from pathlib import Path

import pytest

ROOT = Path(__file__).resolve().parents[1]
sys.path.insert(0, str(ROOT / "src"))


def test_pyproject_declares_lit_gui_entrypoint_and_pyside6_dependency() -> None:
    project = tomllib.loads((ROOT / "pyproject.toml").read_text(encoding="utf-8"))["project"]

